workbox_routing_registerRoute(/^https:\/\/[^/]+\/((?!api\/).)*$/i, new workbox_strategies_NetworkFirst({ "cacheName":"pages-cache","networkTimeoutSeconds":10, plugins: [new workbox_expiration_ExpirationPlugin({ maxEntries: 50, maxAgeSeconds: 86400 })] }), 'GET');




